values
  ('00000000-0000-0000-0000-0000000c0001', null, 'しごとの日本語 ソフトウェア開発プロジェクト', 'ソフトウェア開発プロジェクトの現場で使う日本語を、初回訪問・キックオフから進捗報告・UAT・オンサイト終了まで順番に学ぶコース。', 'しごとの日本語', 'N3-N2', '#6366f1', '/course-covers/it-nihongo.jpg', 0, true)
