  ('00000000-0000-0000-0000-0000000b0013', null, '00000000-0000-0000-0000-0000000c0001', '第13課 – 製品とリリースノート', '会話', 'N3-N2', null, 'upload', null, '/audio/lessons/lesson-13.m4a', true),
  ('00000000-0000-0000-0000-0000000b0014', null, '00000000-0000-0000-0000-0000000c0001', '第14課 – UATサポートタスクの確認', '会話', 'N3-N2', null, 'upload', null, '/audio/lessons/lesson-14.m4a', true),
  ('00000000-0000-0000-0000-0000000b0015', null, '00000000-0000-0000-0000-0000000c0001', '第15課 – オンサイト終了のあいさつ', '敬語', 'N3-N2', null, 'upload', null, '/audio/lessons/lesson-15.m4a', true)
insert into public.lesson_sentences
  (id, lesson_id, order_index, ja_text, vi_translation, audio_url, audio_start, audio_end, pass_score)
values
  ('00000000-0000-0000-0001-000000000001', '00000000-0000-0000-0000-0000000b0001', 0, '私は、E-Learning プロジェクトのPMのアンと申します。どうぞよろしくお願いいたしま す。', 'Tôi là An, PM của dự án E-Learning. Rất mong nhận được sự giúp đỡ', '/audio/lessons/lesson-01/s01.m4a', 7, 17, 80),
  ('00000000-0000-0000-0001-000000000002', '00000000-0000-0000-0000-0000000b0001', 1, '今回のプロジェクト責任者の小巻と申します。どうぞよろしくお願いいたします。', 'Tôi là Komaki, người chịu trách nhiệm dự án lần này. Rất mong nhận được sự giúp đỡ', '/audio/lessons/lesson-01/s02.m4a', 17, 26, 80),
  ('00000000-0000-0000-0001-000000000003', '00000000-0000-0000-0000-0000000b0001', 2, 'この度は、ご来社くださり、 まことにありがとうございます。 日本企業向けシステム開発 部門長をしております、ホアンと申します。どうぞよろしくお願いいたします。', 'Cảm ơn quý anh/chị lần này đã ghé thăm công ty. Tôi là Hoàn, trưởng phòng phát triển hệ thống khối doanh nghiệp Nhật', '/audio/lessons/lesson-01/s03.m4a', 27, 43, 80),
  ('00000000-0000-0000-0001-000000000004', '00000000-0000-0000-0000-0000000b0001', 3, '私は、 SESのIT部門でIT関連のプロジェクトを管理しています、 小巻と申します。どうぞよろしくお願いいたします。', 'Tên tôi là Komaki – quản lý các dự án liên quan đến IT tại bộ phận IT của SES. Cảm ơn quý anh/chị rất nhiều', '/audio/lessons/lesson-01/s04.m4a', 44, 56, 80),
  ('00000000-0000-0000-0001-000000000005', '00000000-0000-0000-0000-0000000b0001', 4, 'よろしくお願いいたします。 私は日本のお客様向けのシステム開発プロジェクトを主に 担当しております。今回のプロジェクトのPMをつとめることになりました､アンと申します。どうぞよろしくお願いいたします。', 'Cảm ơn quý anh/chị. Tôi là người chịu phụ trách chính các dự án phát triển hệ thống cho khách hàng Nhật Bản. Tên tôi là An – PM cho dự án này. Rất mong nhận được sự giúp đỡ', '/audio/lessons/lesson-01/s05.m4a', 58, 78, 80),
  ('00000000-0000-0000-0001-000000000006', '00000000-0000-0000-0000-0000000b0001', 5, '今回は、 皆さんとベトナムでプロジェクトのキックオフをするために参りましたので、2日間どうぞよろしくお願いします。 前回訪問した黒田もぜひよろしくと申しておりました。', 'Lần này tôi đến VN để khởi động dự án cùng mọi người nên rất mong nên 2 ngày tới nhận được sự giúp đỡ của quý vị. Anh Kuroda, người đã đến thăm lần trước cũng bày tỏ lòng biết ơn.', '/audio/lessons/lesson-01/s06.m4a', 78, 95, 80),
  ('00000000-0000-0000-0001-000000000007', '00000000-0000-0000-0000-0000000b0001', 6, 'はい。 弊社も対面でキックオフができ、光栄です。 帰国されたあとに、SEのリーが要件 定義の工程からオンサイトすることになっております。その際もよろしくお願いいたします。', 'Vâng. Chúng tôi cũng rất vinh dự khi có thể trực tiếp họp Kickoff. Sau khi trở về Nhật Bản, anh Ly – sẽ được cử đi onsite để bắt đầu quá trình xác định yêu cầu. Lúc đó cũng rất mong anh giúp đỡ', '/audio/lessons/lesson-01/s07.m4a', 97, 113, 80),
  ('00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0000-0000000b0002', 0, 'では、プロジェクトのキックオフミーティングを始めたいと思います。 よろしくお願いいたします。', 'Tôi xin phép được bắt đầu buổi meeting kickoff', '/audio/lessons/lesson-02/s01.m4a', 9, 18, 80),
  ('00000000-0000-0000-0002-000000000002', '00000000-0000-0000-0000-0000000b0002', 1, 'はい、よろしくお願いいたします。', 'Vâng, xin nhờ anh', '/audio/lessons/lesson-02/s02.m4a', 18, 23, 80),
  ('00000000-0000-0000-0002-000000000003', '00000000-0000-0000-0000-0000000b0002', 2, 'まず、本日のアジェンダについて説明いたします。 最初に、 SES 様にプロジェクトの目的を説明していただきます。 次に、 弊社がキックオフ資料を説明いたします。そして、最後にQ&Aと相談をします。この順番で進めたいと思いますが、よろしいでしょうか。', 'Trước tiên tôi xin phép giải thích về Agenda cuộc họp hôm nay. Đầu tiên phía SES sẽ trình bày về mục đích của dự án. Tiếp đó phía công tu chúng tôi sẽ giải thích tài liệu Kickoff. Và cuối cùng là phần thảo luận và Q&A. Trình tự như vậy anh/chị thấy ok chứ ạ?', '/audio/lessons/lesson-02/s03.m4a', 23, 54, 80),
  ('00000000-0000-0000-0002-000000000004', '00000000-0000-0000-0000-0000000b0002', 3, 'はい。そうしましょう。 ではまず、私から目的についてお話しします。 今回はデジタル教科書のWeb アプリケーションを開発します。 動きのあるUIにすることで、生徒たちが楽しく学べるようにしたいと思っています。', 'Vâng, cùng tiến hành như vậy nhé. Đầu tiên tôi xin nói về mục đích. Lần này, chúng tôi sẽ phát triển một ứng dụng web cho sách giáo khoa điện tử. Bằng cách tạo UI động, chúng tôi muốn tạo niềm vui học tập cho học sinh.', '/audio/lessons/lesson-02/s04.m4a', 54, 78, 80),
  ('00000000-0000-0000-0002-000000000005', '00000000-0000-0000-0000-0000000b0002', 4, 'ご説明ありがとうございます。 それでは、私からキックオフ資料を説明いたします。', 'Cảm ơn chị đã giải thích. Tiếp theo tôi xin giải thích về tài liệu Kickoff', '/audio/lessons/lesson-02/s05.m4a', 78, 86, 80),
  ('00000000-0000-0000-0002-000000000006', '00000000-0000-0000-0000-0000000b0002', 5, 'こちらをご覧ください。 キックオフ資料の内容は､ プロジェクトの概要、 体制、 開発手法、スケジュール、コミュニケーションプラン、リスクと課題です。では、順を追って説明いたします。', 'Xin hãy quan sát vào đây. Nội dung của tài liệu kickoff gồm Overview về dự án, cấu trúc, phương pháp phát triển, Schedule, kế hoạch giao tiếp, các rủi ro và vấn đề.Tôi xin được giải thích từng bước.', '/audio/lessons/lesson-02/s06.m4a', 88, 109, 80),
  ('00000000-0000-0000-0002-000000000007', '00000000-0000-0000-0000-0000000b0002', 6, 'はい。お願いします。', 'Vâng, xin nhờ anh', '/audio/lessons/lesson-02/s07.m4a', 109, 113, 80),
  ('00000000-0000-0000-0002-000000000008', '00000000-0000-0000-0000-0000000b0002', 7, 'まず、プロジェクト概要についてです。 今回のE-Learning プロジェクトは、 Web アプリを開発するプロジェクトです。既存システムをベースに、 WebGLを取り入れて機能追加と変更をします。', 'Đầu tiên là về Overview dự án. Dự án E-learning lần này là một dự án phát triển web-app. Dựa trên hệ thống hiện có, chúng tôi kết hợp WebGL để update và bổ sung thêm chức năng.', '/audio/lessons/lesson-02/s08.m4a', 113, 132, 80),
  ('00000000-0000-0000-0003-000000000001', '00000000-0000-0000-0000-0000000b0003', 0, '次に、マスタースケジュールと進め方について説明いたします。 開発期間は4月1日から7月8日までです。 SRS, UIなどインプットは御社より提供していただき、弊社がコーディング、 UT、IT をベトナムで行います。 SEのリーは要件定義からオンサイトし、UAT とデプロイメントもサポートします。', 'Tiếp theo tôi sẽ trình bày về kế hoạch tổng thể và cách tiến hành. Thời gian phát triển là từ 1/4 đến 8/7. Các tài liệu đầu vào như SRS, UI thì phía quý công ty sẽ cung cấp, còn phía công ty chúng tôi sẽ tiến hành code, UnitTest, InterarationTest ở VN. Anh Ly – nhân viên SE sẽ onsite hỗ trợ từ giai đoạn định nghĩa yêu cầu, UAT và cả Deployment', '/audio/lessons/lesson-03/s01.m4a', 0, 45, 80),
  ('00000000-0000-0000-0003-000000000002', '00000000-0000-0000-0000-0000000b0003', 1, 'はい。 SRSは完成しましたので、明日説明します。 UIは弊社で準備していますが、開発期間中、ロジックに合わせて直したほうがよいものがありましたら、教えていただければと思います。', 'Vâng. SRS đã hoàn thành, ngày mai chúng tôi sẽ giải thích. UI thì công ty chúng tôi đang chuẩn bị, nếu có bất kỳ điều gì cần sửa đổi để phù hợp với logic trong quá trình phát triển, vui lòng cho chúng tôi biết.', '/audio/lessons/lesson-03/s02.m4a', 45, 66, 80),
  ('00000000-0000-0000-0003-000000000003', '00000000-0000-0000-0000-0000000b0003', 2, '承知しました。 開発手法に関しては要件がかなりはっきりしているので、ウォーターフォールで開発を進めます。', 'Tôi hiểu rồi. Về phương pháp phát triển, các yêu cầu khá rõ ràng nên chúng tôi sẽ tiến hành phát triển bằng mô hình Waterfall', '/audio/lessons/lesson-03/s03.m4a', 67, 81, 80),
  ('00000000-0000-0000-0003-000000000004', '00000000-0000-0000-0000-0000000b0003', 3, 'はい。そうですね。 少しは要件の変更が発生するかもしれませんが、 ほぼ決まっていますので、それで問題ないと思います。', 'Vâng. Tôi đồng ý. Có thể sẽ có phát sinh 1 vài update về yêu cầu, nhưng hầu hết yêu cầu đã được quyết định nên tôi nghĩ không có vấn đề gì', '/audio/lessons/lesson-03/s04.m4a', 81, 95, 80),
  ('00000000-0000-0000-0003-000000000005', '00000000-0000-0000-0000-0000000b0003', 4, 'はい。ありがとうございます。 また、UI が御社の期待通りになっているかをチェックするため、3回のデモを実施することを提案します。 そこで、修正すべき点を確認し、必要であれば修正します。 そうすれば、手戻りを減らせると考えています。', 'Vâng. Xin cảm ơn. Thêm nữa chúng tôi đề xuất thực hiện demo 3 lần để check giao diện UI có đáp ứng mong đợi của công ty bạn hay không. tại demo xác nhận điểm cần chỉnh sửa, nếu cần thiết chúng tôi sẽ sửa. Tôi tin rằng điều này sẽ làm giảm việc phải làm lại.', '/audio/lessons/lesson-03/s05.m4a', 95, 121, 80),
  ('00000000-0000-0000-0003-000000000006', '00000000-0000-0000-0000-0000000b0003', 5, 'そうですね。 賛成です。実は、SRS で一部決まっていない内容があります。 デモで何を改善すればよいか、はっきり見えるようになり、より良い製品ができると思いますので、ぜひ行いましょう。', 'Vâng. Tôi tán thành. Thực ra là, có 1 vài phần nội dung SRS chưa được quyết định. Tôi nghĩ demo sẽ giúp thấy rõ những gì cần cải thiện và tạo ra sản phẩm tốt hơn nên nhất định hãy tiến hành demo', '/audio/lessons/lesson-03/s06.m4a', 121, 142, 80),
  ('00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0000-0000000b0004', 0, 'ここまでプロジェクト概要と開発手法について説明しましたが、 何かご質問はありますか。 ご質問がなければ、体制とメンバーについて紹介いたします。', 'Chúng tôi đã giải thích tổng quan về dự án và phương pháp phát triển cho đến thời điểm này, các bạn có thắc mắc gì không? Nếu bạn không có câu hỏi nào, tôi xin giới thiệu cơ cấu và thành viên của chúng tôi.', '/audio/lessons/lesson-04/s01.m4a', 10, 28, 80),
  ('00000000-0000-0000-0004-000000000002', '00000000-0000-0000-0000-0000000b0004', 1, 'ここまでは問題ないので、続けてください。', 'Cho đến nay không có vấn đề gì, vì vậy hãy tiếp tục.', '/audio/lessons/lesson-04/s02.m4a', 28, 34, 80),
  ('00000000-0000-0000-0004-000000000003', '00000000-0000-0000-0000-0000000b0004', 2, 'はい。こちらがプロジェクトの体制です。 黒田様がプロジェクト統括管理者で、小巻様が御社のPMです。このプロジェクトに関係する課題などは私が小巻様と確認すればよいという理解ですが、間違いないでしょうか。', 'Vâng. Đây là cấu trúc của dự án. Ông Kuroda là tổng phụ trách dự án, chị Komaki là PM của công ty bạn. Tôi đang hiểu rằng tôi có thể xác nhận các vấn đề liên quan đến dự án này với chị Komaki, có đúng không ạ?', '/audio/lessons/lesson-04/s03.m4a', 34, 61, 80),
  ('00000000-0000-0000-0004-000000000004', '00000000-0000-0000-0000-0000000b0004', 3, 'はい。 その通りです。 今回のプロジェクトは設計工程がなく、 何度かデモをしてお互いの認識を確認するという方法で進めます。 そうすると、ひんぱんに質問のやりとりをする必要が出てくると思います。 日本にはリーさんもいらっしゃいますし、確認したいことがあったら、いつでもけっこうですので、遠慮なく聞いてください。', 'Vâng. Đúng vậy. Dự án lần này không có công đoạn thiết kế và chúng ta sẽ tiến hành một số buổi demo để xác nhận sự hiểu biết của nhau. Vì thế, tôi nghĩ chúng ta cần phải trao đổi hỏi đáp thường xuyên. Anh Lee cũng đang ở Nhật Bản nên nếu có thắc mắc gì xin vui lòng hỏi.', '/audio/lessons/lesson-04/s04.m4a', 61, 94, 80),
  ('00000000-0000-0000-0004-000000000005', '00000000-0000-0000-0000-0000000b0004', 4, 'はい。ありがとうございます。 オフショアの体制ですが、 統括管理者はホアンです。PMは私アンで、開発、テスト、 コミュニケーション、品質保証の4つのチームを管理します。そして、SEのリーが御社にオンサイトします。 レポートラインですが、メンバーがチームリーダーに報告し、チームリーダーが私に報告します。私がそれらの情報をまとめて、小巻様に報告します。', 'Vâng. Xin cảm ơn. Về cơ cấu Offshore thì tổng phụ trách là anh Hoàn. Tôi là An, là PM quản lý 4 nhóm: Dev, Tester, Comtor và QA. Và có anh Lee – SE sẽ onsite tại công ty bạn. Về luồng report thì các thành viên báo cáo với leader, leader báo cáo với tôi. Tôi sẽ tổng hợp thông tin và báo cáo với chị Komaki.', '/audio/lessons/lesson-04/s05.m4a', 94, 138, 80),
  ('00000000-0000-0000-0004-000000000006', '00000000-0000-0000-0000-0000000b0004', 5, 'わかりました。 レポートラインについては弊社も同じ認識です。', 'Tôi hiểu rồi. Về luồng report thì công ty chúng tôi cũng nhận thức như vậy', '/audio/lessons/lesson-04/s06.m4a', 138, 146, 80),
  ('00000000-0000-0000-0004-000000000007', '00000000-0000-0000-0000-0000000b0004', 6, '技術的な問題は、私もしくはリーが確認します。 営業と契約に関しては当初から御社とやりとりをさせていただいているリンが引き続き担当します。 プロジェクトで解決の難しい課題があれば、黒田様、 ホアンにエスカレーションします。場合によっては、リンも参加いたします。', 'Mọi vấn đề technical sẽ được tôi hoặc Lee kiểm tra. Về vấn đề hợp đồng và business thì do chị Linh, người đã làm việc với công ty của bạn ngay từ đầu sẽ tiếp tục phụ trách. Trong dự án nếu có vấn đề khó giải quyết, tôi sẽ báo cáo vấn đề đó với ông Kuroda và anh Hoàn. Trong một số trường hợp, Linh cũng sẽ tham gia.', '/audio/lessons/lesson-04/s07.m4a', 146, 180, 80),
  ('00000000-0000-0000-0004-000000000008', '00000000-0000-0000-0000-0000000b0004', 7, 'はい。わかりました。 ご説明ありがとうございました。', 'Vâng, tôi rõ rồi. Cảm ơn anh đã giải thích', '/audio/lessons/lesson-04/s08.m4a', 180, 186, 80),
  ('00000000-0000-0000-0005-000000000001', '00000000-0000-0000-0000-0000000b0005', 0, '紹介します。 プロジェクト実施のためにベトナムから来てくださった DKH 社のリーさんです。 本日からこちらで勤務していただきます。 では、リーさん、簡単に自己紹介をお願いします。', 'Xin giới thiệu, đây là chị Ly đến từ DKH, người đến từ Việt Nam để thực hiện dự án. Chị ấy sẽ làm việc ở đây từ hôm nay. Chị Ly, xin vui lòng giới thiệu ngắn gọn về bản thân.', '/audio/lessons/lesson-05/s01.m4a', 5.84, 21.52, 80),
  ('00000000-0000-0000-0005-000000000002', '00000000-0000-0000-0000-0000000b0005', 1, '本日よりお世話になります。 ベトナムから参りました、リーと申します。 DKH でSEをしております。 日本は初めてですので、わからないことも多いかと思いますが、どうぞよろしくお願いいたします。', 'Từ hôm nay rất mong được giúp đỡ, tôi là Ly đến từ Việt Nam. Tôi làm SE ở DKH. Lần đầu tới Nhật có nhiều điều chưa rõ, rất mong các anh/chị giúp đỡ.', '/audio/lessons/lesson-05/s02.m4a', 21.52, 36.88, 80),
  ('00000000-0000-0000-0005-000000000003', '00000000-0000-0000-0000-0000000b0005', 2, '困ったことがあったら、私や山本に遠慮なく相談してください。', 'Có gì khó khăn thì cứ thảo luận với tôi hoặc anh Yamamoto, đừng ngại.', '/audio/lessons/lesson-05/s03.m4a', 36.88, 43.48, 80),
  ('00000000-0000-0000-0005-000000000004', '00000000-0000-0000-0000-0000000b0005', 3, 'はい。ありがとうございます。 こちらはホアンからのおみやげです。 どうぞ皆さんで召し上がってください。 ホアンも皆さんによろしくと申しておりました。', 'Vâng, xin cảm ơn. Đây là quà của anh Hoàn. Xin mời mọi người ạ. Anh Hoàn cũng gửi lời chúc tới mọi người', '/audio/lessons/lesson-05/s04.m4a', 43.48, 56.98, 80),
  ('00000000-0000-0000-0005-000000000005', '00000000-0000-0000-0000-0000000b0005', 4, 'お気遣いありがとうございます。 これはベトナムで有名なお菓子か何かですか。', 'Cảm ơn vì sự quan tâm của bạn. Đây là loại bánh kẹo nổi tiếng gì của Việt Nam à?', '/audio/lessons/lesson-05/s05.m4a', 56.98, 64.74, 80),
  ('00000000-0000-0000-0005-000000000006', '00000000-0000-0000-0000-0000000b0005', 5, 'はい。 北部の名物で、緑豆からできたお菓子です。', 'Vâng, đây là đặc sản của miền bắc, một loại bánh làm từ đậu xanh', '/audio/lessons/lesson-05/s06.m4a', 64.74, 70.62, 80),
  ('00000000-0000-0000-0005-000000000007', '00000000-0000-0000-0000-0000000b0005', 6, 'ところで、御社のルールについて教えていただけますか。', 'Nhân tiện, bạn có thể cho tôi biết về nội quy của công ty được không?', '/audio/lessons/lesson-05/s07.m4a', 70.62, 76.58, 80),
  ('00000000-0000-0000-0005-000000000008', '00000000-0000-0000-0000-0000000b0005', 7, 'そうですね。 山本から説明しましょう。', 'Vâng, anh Yamamoto sẽ giải thích cho bạn', '/audio/lessons/lesson-05/s08.m4a', 76.58, 81.7, 80),
  ('00000000-0000-0000-0005-000000000009', '00000000-0000-0000-0000-0000000b0005', 8, 'まず、勤務時間は、朝9時から夕方6時までです。 だいたい皆さん 10分前には出社しています。', 'Trước hết, giờ làm việc là từ 9 giờ sáng đến 6 giờ chiều. Hầu hết mọi người đến nơi làm việc sớm 10 phút.', '/audio/lessons/lesson-05/s09.m4a', 81.7, 92.18, 80),
  ('00000000-0000-0000-0005-000000000010', '00000000-0000-0000-0000-0000000b0005', 9, '承知しました。 9時から6時までですね。 お昼休みは何時から取ればよいですか。', 'Tôi hiểu rồi. Từ 9 giờ sáng đến 6 giờ chiều nhỉ. Nghỉ trưa thì vào lúc mấy giờ vậy?', '/audio/lessons/lesson-05/s10.m4a', 92.18, 100.58, 80),
  ('00000000-0000-0000-0005-000000000011', '00000000-0000-0000-0000-0000000b0005', 10, '一応12時から1時ですが、外のお店は混むので、少しずらして取っても問題ありません。', 'Đáng lẽ là từ 12h đến 1h nhưng các quán rất đông nên dời thời gian khác một chút cũng không sao.', '/audio/lessons/lesson-05/s11.m4a', 100.58, 110.5, 80),
  ('00000000-0000-0000-0005-000000000012', '00000000-0000-0000-0000-0000000b0005', 11, 'ずらしてというのは、どういうことですか。', 'Dời thời gian là sao ạ?', '/audio/lessons/lesson-05/s12.m4a', 110.5, 115.3, 80),
  ('00000000-0000-0000-0005-000000000013', '00000000-0000-0000-0000-0000000b0005', 12, '例えば、12時半から1時半にするとか、1時から2時にしてもかまわないということです。 1時間であればよいです。 会議室と給湯室へも案内しましょう。', 'Ví dụ: có thể từ 12:30 đến 1:30 hoặc từ 1:00 đến 2:00. Trong khoảng 1 tiếng là được. Tôi cũng sẽ dẫn bạn đến phòng họp và phòng bếp pha trà.', '/audio/lessons/lesson-05/s13.m4a', 115.3, 132.18, 80),
  ('00000000-0000-0000-0006-000000000001', '00000000-0000-0000-0000-0000000b0006', 0, 'こちらの会議室はIT部門の専用です。 使いたいときは、事前に会議室予約システムから予約してください。後で予約サイトのリンクを送っておきますね。', 'Phòng họp này dành riêng cho bộ phận CNTT. Nếu bạn muốn sử dụng, vui lòng đặt chỗ trước thông qua hệ thống đặt phòng hội nghị. Tôi sẽ gửi cho bạn link trang đặt phòng sau.', '/audio/lessons/lesson-06/s01.m4a', 0, 16, 80),
  ('00000000-0000-0000-0006-000000000002', '00000000-0000-0000-0000-0000000b0006', 1, 'はい。 オフショアチームとの会議もあるので、ありがとうございます。', 'Vâng. Tôi cũng có cuộc họp với team Offshore, vì vậy cảm ơn bạn rất nhiều.', '/audio/lessons/lesson-06/s02.m4a', 16, 22, 80),
  ('00000000-0000-0000-0006-000000000003', '00000000-0000-0000-0000-0000000b0006', 2, 'こちらは給湯室です。 このポットのお湯は自由にお使いください。そして、冷蔵庫は共用ですので、ものを入れるときは自分の名前を書いて、賞味期限切れのものは処分するようにしてくださいね。 ごみは生ごみやペットボトルなどに分別することになっています。', 'Đây là phòng pha trà. Hãy dùng nước nóng ở đây tự nhiên. Ngoài ra, tủ lạnh được dùng chung nên hãy viết tên bạn lên đó khi cho đồ vào và nhớ vứt bỏ những đồ đã hết hạn sử dụng. Rác thải sẽ cần phân loại thành rác thải thực phẩm, chai nhựa, v.v.', '/audio/lessons/lesson-06/s03.m4a', 23, 49, 80),
  ('00000000-0000-0000-0006-000000000004', '00000000-0000-0000-0000-0000000b0006', 3, '分別というのは、ものによって、これらのごみ箱に分けて捨てるということですね。', 'Phân loại có nghĩa là vứt bỏ các vật phẩm khác nhau vào các thùng khác nhau nhỉ', '/audio/lessons/lesson-06/s04.m4a', 49, 57, 80),
  ('00000000-0000-0000-0006-000000000005', '00000000-0000-0000-0000-0000000b0006', 4, 'そうです。他になにか気になることはありますか。', 'Ngoài ra chị còn lo lắng điều gì không?', '/audio/lessons/lesson-06/s05.m4a', 57, 63, 80),
  ('00000000-0000-0000-0006-000000000006', '00000000-0000-0000-0000-0000000b0006', 5, 'すぐには思いつかないので、 逆に質問してもよいですか。 御社で他になにか気をつけた方がよいことはありませんか。', 'Giờ tôi không nghĩ được luôn, trái lại tôi muốn hỏi 1 câu hỏi được không? Ở công ty anh có điều gì nên lưu ý hay không?', '/audio/lessons/lesson-06/s06.m4a', 63, 75, 80),
  ('00000000-0000-0000-0006-000000000007', '00000000-0000-0000-0000-0000000b0006', 6, 'そうですね。 整理整頓とセキュリティですかね。席を離れるときは、机の上に社外秘の資料などを置いたままにしないようにしてください。 また、退社するときは、ノートパソコンを鍵付きロッカーに入れて帰ってください。', 'À, về an toàn vệ sinh và bảo mật nhỉ? Khi rời khỏi bàn làm việc, vui lòng không để lại tài liệu mật trên bàn làm việc. Ngoài ra, khi tan làm, vui lòng cất máy tính xách tay của bạn vào tủ có khóa.', '/audio/lessons/lesson-06/s07.m4a', 75, 96, 80),
  ('00000000-0000-0000-0006-000000000008', '00000000-0000-0000-0000-0000000b0006', 7, 'はい。 気をつけます。', 'Vâng, tôi sẽ chú ý', '/audio/lessons/lesson-06/s08.m4a', 96, 99, 80),
  ('00000000-0000-0000-0006-000000000009', '00000000-0000-0000-0000-0000000b0006', 8, 'では、席に戻ってパソコンの設定をしましょうか。 弊社で指定されているウイルス対策ソフトやメール誤送信防止ツールをインストールしましょう。', 'Vậy giờ chúng ta cùng về chỗ và cài đặt máy tính. Vui lòng cài đặt tool ngăn chặn việc gửi email sai, và các phần mềm diệt virus do công ty chúng tôi chỉ định.', '/audio/lessons/lesson-06/s09.m4a', 99, 114, 80),
  ('00000000-0000-0000-0006-000000000010', '00000000-0000-0000-0000-0000000b0006', 9, 'これが持参したノートパソコンです。ベトナムにいる間に、 必要なデータはバックアップを取ってあります。', 'Đây là chiếc máy tính xách tay tôi mang theo. Khi ở Việt Nam, tôi đã sao lưu những dữ liệu cần thiết.', '/audio/lessons/lesson-06/s10.m4a', 114, 124, 80),
  ('00000000-0000-0000-0006-000000000011', '00000000-0000-0000-0000-0000000b0006', 10, 'では、一度お預かりしましょう。 弊社では、IT部門のセキュリティチェックを受けてからでないと、社内で使ってはいけないことになっています。', 'Thôi tạm thời giữ nó đã. Tại công ty của chúng tôi, chúng tôi phải trải qua quá trình kiểm tra bảo mật bởi bộ phận CNTT trước khi sử dụng nội bộ.', '/audio/lessons/lesson-06/s11.m4a', 124, 137, 80),
  ('00000000-0000-0000-0006-000000000012', '00000000-0000-0000-0000-0000000b0006', 11, '承知しました。 では、お願いします。', 'Vâng, xin nhờ anh', '/audio/lessons/lesson-06/s12.m4a', 137, 142, 80),
  ('00000000-0000-0000-0007-000000000001', '00000000-0000-0000-0000-0000000b0007', 0, 'プロジェクトのメンバーが全員そろいましたので、要件の説明会を始めたいと思います。説明の中で、わかりにくいところや確認しておきたいことがありましたら、その場で質問してください。', 'Tất cả member đã có mặt nên tôi xin bắt đầu cuộc họp giải thích yêu cầu. Trong lúc giải thích có chỗ nào khó hiểu hay có gì cần xác nhận thì anh hãy hỏi ở đấy nhé.', '/audio/lessons/lesson-07/s01.m4a', 0, 20, 80),
  ('00000000-0000-0000-0007-000000000002', '00000000-0000-0000-0000-0000000b0007', 1, '承知しました。 よろしくお願いいたします。', 'Vâng tôi biết rồi, cảm ơn chị', '/audio/lessons/lesson-07/s02.m4a', 20, 25, 80),
  ('00000000-0000-0000-0007-000000000003', '00000000-0000-0000-0000-0000000b0007', 2, '昨年は、デジタル教科書のデスクトップアプリケーションを開発していただき、ありがとうございました。 キックオフミーティングで説明した通り、今回はこのアプリをベースに、WebGL を使用してアプリを Web 化し、一部機能の追加・修正を行います。', 'Cảm ơn năm ngoái phía bên anh đã phát triển app desktop giáo trình điện tử. Như đã giải thích tại kickoff meeting, lần này chúng tôi sẽ base trên ứng dụng này, biến nó thành web bằng WebGL, đồng thời thêm và sửa đổi một số chức năng.', '/audio/lessons/lesson-07/s03.m4a', 25, 49, 80),
  ('00000000-0000-0000-0007-000000000004', '00000000-0000-0000-0000-0000000b0007', 3, 'まず、 今回の Web 版の画面について説明します。 お見せしているファイルは昨年開発されたアプリの資料なので、皆さんにとってはなじみのあるものだと思います。 新規画面には、「新規」 と、 Web版で実装しなくてよいものには 「Web 化対象外」 と追記しました。', 'Đầu tiên tôi sẽ giải thích về màn hình của phiên bản web này. File tôi đang cho bạn xem là app được phát triển năm ngoái, vì vậy chắc chắn là chúng quen thuộc với các anh. Với các màn mới chúng tôi đã thêm vào danh mục “新規”, và với các mục không cần triển khai trên bản web thì thêm vào danh mục “Web 化対象外”.', '/audio/lessons/lesson-07/s04.m4a', 49, 79, 80),
  ('00000000-0000-0000-0007-000000000005', '00000000-0000-0000-0000-0000000b0007', 4, 'はい。 「新規」 または 「Web 化対象外」 の追記がない場合は、 以前のアプリと同じ画面にするということですね。', 'Vâng. Nếu không tính phần danh mục “新規” và “Web 化対象外” thì các màn hình sẽ giống như ứng dụng trước đó nhỉ.', '/audio/lessons/lesson-07/s05.m4a', 79, 91, 80),
  ('00000000-0000-0000-0007-000000000006', '00000000-0000-0000-0000-0000000b0007', 5, 'その通りです。', 'Đúng như vậy', '/audio/lessons/lesson-07/s06.m4a', 91, 94, 80),
  ('00000000-0000-0000-0007-000000000007', '00000000-0000-0000-0000-0000000b0007', 6, 'また、機能の修正点がいくつかあるので、別のファイルにまとめました。', 'Thêm nữa còn một số chỗ chức năng cần sửa tôi đã biên soạn thành một file riêng.', '/audio/lessons/lesson-07/s07.m4a', 94, 102, 80),
  ('00000000-0000-0000-0007-000000000008', '00000000-0000-0000-0000-0000000b0007', 7, 'はい。「Web _ 修正点」というものですか。', 'Vâng, ở file “Web _ 修正点” đúng không ạ?', '/audio/lessons/lesson-07/s08.m4a', 102, 108, 80),
  ('00000000-0000-0000-0007-000000000009', '00000000-0000-0000-0000-0000000b0007', 8, 'はい、そうです。', 'Vâng, đúng rồi', '/audio/lessons/lesson-07/s09.m4a', 108, 111, 80),
  ('00000000-0000-0000-0007-000000000010', '00000000-0000-0000-0000-0000000b0007', 9, 'そのファイルであれば、すでに読んでいますので、この場で説明していただかなくても問題ありません。疑問点がでてきたら、確認させてください。', 'Nếu là file đó thì chúng tôi đã đọc rồi nên không cần giải thích ở đây cũng được. Nếu có thắc mắc gì tôi lại xin phép xác nhận', '/audio/lessons/lesson-07/s10.m4a', 111, 126, 80),
  ('00000000-0000-0000-0007-000000000011', '00000000-0000-0000-0000-0000000b0007', 10, 'わかりました。 今後、実装中に何かありましたら、遠慮なくいつでも聞いてください。', 'Tôi hiểu rồi. Trong quá trình thực hiện nếu có thắc mắc xin vui lòng hỏi.', '/audio/lessons/lesson-07/s11.m4a', 126, 135, 80),
  ('00000000-0000-0000-0008-000000000001', '00000000-0000-0000-0000-0000000b0008', 0, 'こんにちは。 御社は小巻様のみが参加されるのでしょうか。', 'Xin chào, quý công ty chỉ có chị Komaki join họp đúng không ạ?', '/audio/lessons/lesson-08/s01.m4a', 0, 14, 80),
  ('00000000-0000-0000-0008-000000000002', '00000000-0000-0000-0000-0000000b0008', 1, 'はい、そうです。 私だけです。', 'Vâng, có mỗi tôi thôi', '/audio/lessons/lesson-08/s02.m4a', 14, 18, 80),
  ('00000000-0000-0000-0008-000000000003', '00000000-0000-0000-0000-0000000b0008', 2, '弊社は全員そろいましたので会議を始めたいと思います。 よろしくお願いいたします。', 'Phía công ty tôi mọi người sẵn sàng cả rồi nên chúng ta bắt đầu nhé', '/audio/lessons/lesson-08/s03.m4a', 18, 24, 80),
  ('00000000-0000-0000-0008-000000000004', '00000000-0000-0000-0000-0000000b0008', 3, 'はい、よろしくお願いいたします。', 'Vâng, xin nhờ anh', '/audio/lessons/lesson-08/s04.m4a', 24, 28, 80),
  ('00000000-0000-0000-0008-000000000005', '00000000-0000-0000-0000-0000000b0008', 4, '昨日の夕方に進捗の詳細をまとめた WBS と進捗報告書を送付しました。', 'Tối hôm qua, chúng tôi đã gửi báo cáo tiến độ và WBS chi tiết tiến độ', '/audio/lessons/lesson-08/s05.m4a', 28, 44, 80),
  ('00000000-0000-0000-0008-000000000006', '00000000-0000-0000-0000-0000000b0008', 5, 'はい、受け取ってざっと確認しました。', 'Vâng, tôi đã nhận được và check nhanh qua', '/audio/lessons/lesson-08/s06.m4a', 44, 50, 80),
  ('00000000-0000-0000-0008-000000000007', '00000000-0000-0000-0000-0000000b0008', 6, 'それでは、画面共有をして報告いたします。内容は進捗報告、リスク・課題とQ&Aの3つです。 まず、 3.3 3.4の2つの実装タスクを除いて、 全体の進捗は計画通りです。 開発環境の調査と構築、 パフォーマンス改善は完了しました。', 'Bây giờ tôi sẽ share màn hình và báo cáo. Nội dung bao gồm ba phần: báo cáo tiến độ, risk/issue và Q&A. Trước hết, ngoại trừ 2 task 3.3 và 3.4 thì tiến độ tổng thể đều đúng kế hoạch. Nghiên cứu, xây dựng môi trường phát triển và cải tiến performance đã hoàn thành.', '/audio/lessons/lesson-08/s07.m4a', 51, 84, 80),
  ('00000000-0000-0000-0008-000000000008', '00000000-0000-0000-0000-0000000b0008', 7, '現在は、画面の実装と結合テスト仕様書作成を進めています。 画面の実装は50%結合テスト仕様書の作成は30%完了しました。進捗の詳細は WBS ファイルをご確認ください。', 'Hiện tại, chúng tôi đang tạo test spec IT và implement màn hình. Code màn hình hoàn thành 50%, IT test spec hoàn thành 30%. Chi tiết tiến độ vui lòng xem ở file WBS', '/audio/lessons/lesson-08/s08.m4a', 84, 110, 80),
  ('00000000-0000-0000-0008-000000000009', '00000000-0000-0000-0000-0000000b0008', 8, '承知しました。 実装は全体で50%ということでしたが、 どの機能も順調に進んでいるのですか。', 'Tôi hiểu rồi. Implement tổng thể là 50%, nhưng tất cả function đều đang suôn sẻ không?', '/audio/lessons/lesson-08/s09.m4a', 110, 122, 80),
  ('00000000-0000-0000-0008-000000000010', '00000000-0000-0000-0000-0000000b0008', 9, '現在、4つの機能の実装タスクを並行して進めています。 そのうち、一つのタスク は完了しており、1つが実施中、2つが遅延です。', 'Chúng tôi hiện đang implement song song 4 task code function. Trong số này, 1 task đã hoàn thành, 1 task đang thực hiện và 2 task đang chậm.', '/audio/lessons/lesson-08/s10.m4a', 122, 139, 80),
  ('00000000-0000-0000-0008-000000000011', '00000000-0000-0000-0000-0000000b0008', 10, '遅延のタスクがあるんですね。 それについて詳しく教えていただけますか。 週報を見ると、確かに 3.3番の「学習データ保存」は50%、 3.4番の「学習の結果」 は0%で、 赤字になっていますね。', 'Có task đang chậm nhỉ. Hãy cho tôi biết chi tiết được không? Nhìn vào báo cáo hàng tuần thì đúng là số 3.3, “Lưu dữ liệu học tập” là 50%, và số 3.4, “Kết quả học tập” là 0%, có màu đỏ.', '/audio/lessons/lesson-08/s11.m4a', 139, 163, 80),
  ('00000000-0000-0000-0008-000000000012', '00000000-0000-0000-0000-0000000b0008', 11, 'はい、その通りです。 学習データ保存、 学習の結果の実装で課題が発生しています。', 'Đúng vậy, đang phát sinh issue khi implement tính năng “Lưu dữ liệu học tập” và “Kết quả học tập”', '/audio/lessons/lesson-08/s12.m4a', 163, 173, 80),
  ('00000000-0000-0000-0009-000000000001', '00000000-0000-0000-0000-0000000b0009', 0, 'メモリ不足の課題が発生していると聞いていますが、状況を教えてもらえますか。', 'Tôi nghe nói có vấn đề là không đủ bộ nhớ. Bạn có thể vui lòng cho tôi biết tình hình không?', '/audio/lessons/lesson-09/s01.m4a', 5.4, 14.6, 80),
  ('00000000-0000-0000-0009-000000000002', '00000000-0000-0000-0000-0000000b0009', 1, 'はい。ここは、以前のデスクトップアプリのときは、静的データをRAM に保存する方法で、問題ありませんでした。 ですが、Webの開発では、その方法だとメモリ不足になります。', 'Vâng. Trước đó ở app desktop, dữ liệu tĩnh được lưu trong RAM và không có vấn đề gì. Tuy nhiên, trong phát triển web, dùng phương pháp nàythì không đủ bộ nhớ', '/audio/lessons/lesson-09/s02.m4a', 14.6, 34.6, 80),
  ('00000000-0000-0000-0009-000000000003', '00000000-0000-0000-0000-0000000b0009', 2, 'メモリ不足が原因で、 一部の画面がデスクトップアプリと同じように動作しないのですね。', 'Vì không đủ bộ nhớ nên một số màn hình không hoạt động được như app desktop nhỉ', '/audio/lessons/lesson-09/s03.m4a', 34.6, 45, 80),
  ('00000000-0000-0000-0009-000000000004', '00000000-0000-0000-0000-0000000b0009', 3, 'はい。そのとおりです。 弊社で調査した結果、 静的データを使う代わりにindexedDB という API にデータを保存すれば、解決することがわかりました。 現在、この対策で実装を進めています。', 'Vâng. Đúng thế. Theo kết quả điều tra, chúng tôi nhận thấy rằng vấn đề có thể được giải quyết bằng cách lưu trữ dữ liệu trong API có tên là indexedDB thay vì sử dụng dữ liệu tĩnh. Chúng tôi hiện đang tiến hành implement biện pháp này.', '/audio/lessons/lesson-09/s04.m4a', 45, 69, 80),
  ('00000000-0000-0000-0009-000000000005', '00000000-0000-0000-0000-0000000b0009', 4, 'わかりました。 Web では indexedDB を使えば、問題なく動くということですね。それで、全体の進捗には影響しませんか。', 'Tôi hiểu rồi. Thế nếu sử dụng indexedDB trên web, nó sẽ hoạt động mà không gặp vấn đề gì nhỉ. Vậy tiến độ chung có bị ảnh hưởng không?', '/audio/lessons/lesson-09/s05.m4a', 69, 83, 80),
  ('00000000-0000-0000-0009-000000000006', '00000000-0000-0000-0000-0000000b0009', 5, 'これらのタスクは予定より2人日遅延していますが、 代わりに結合テスト仕様書の作成を前倒しして対応しております。 そのため、全体の進捗には影響しません。ここの遅延は来週中に取り戻す予定です。', 'Task này chậm hơn hai ngày so với plan nhưng thay vào đó, chúng tôi đã tiến hành tạo ra đặc tả Intergration test. Vì vậy, nó không ảnh hưởng đến tiến độ chung. Chúng tôi dự định sẽ bù đắp cho mọi sự chậm trễ ở này trong tuần tới.', '/audio/lessons/lesson-09/s06.m4a', 83, 109, 80),
  ('00000000-0000-0000-0009-000000000007', '00000000-0000-0000-0000-0000000b0009', 6, 'はい。では引き続き対応していただいて、 また何か問題があれば、ご連絡お願いします。', 'Vâng. Cảm ơn bạn đã tiếp tục hỗ trợ và nếu bạn có thêm bất kỳ vấn đề nào, vui lòng liên hệ với chúng tôi.', '/audio/lessons/lesson-09/s07.m4a', 109, 119, 80),
  ('00000000-0000-0000-0009-000000000008', '00000000-0000-0000-0000-0000000b0009', 7, 'はい。 承知しました。', 'Vâng', '/audio/lessons/lesson-09/s08.m4a', 119, 123, 80),
  ('00000000-0000-0000-0009-000000000009', '00000000-0000-0000-0000-0000000b0009', 8, '他に何か課題はありますか。', 'Ngoài ra còn vấn đề gì không?', '/audio/lessons/lesson-09/s09.m4a', 123, 127, 80),
  ('00000000-0000-0000-0010-000000000001', '00000000-0000-0000-0000-0000000b0010', 0, '最後に1点だけお願いがあるのですが、よろしいですか。', 'Còn 1 điểm cuối tôi muốn xác nhận, có tiện không ạ?', '/audio/lessons/lesson-10/s01.m4a', 6, 13, 80),
  ('00000000-0000-0000-0010-000000000002', '00000000-0000-0000-0000-0000000b0010', 1, 'はい、荷でしょう。', 'Vâng, sao vậy ạ?', '/audio/lessons/lesson-10/s02.m4a', 13, 17, 80),
  ('00000000-0000-0000-0010-000000000003', '00000000-0000-0000-0000-0000000b0010', 2, '昨日、Q&A ファイルに5番~8番の4件の質問を追加しましたので、今週金曜日までにご回答いただけますか。', 'Hôm qua file QA có thêm 4 câu từ câu 5~8 thì đến thứ 6 tuần này chị trả lời giúp chúng tôi được không?', '/audio/lessons/lesson-10/s03.m4a', 17, 26, 80),
  ('00000000-0000-0000-0010-000000000004', '00000000-0000-0000-0000-0000000b0010', 3, '今まだ時間があるので、すぐ確認して、回答できる範囲で回答したいですが、いかがですか。', 'Bây giờ cũng ko có thời gian, tôi sẽ trả lời trong phạm vi có thể trả lời được không?', '/audio/lessons/lesson-10/s04.m4a', 26, 41, 80),
  ('00000000-0000-0000-0010-000000000005', '00000000-0000-0000-0000-0000000b0010', 4, 'はい、ではQ&A ファイルを映しますので、少しお待ちください。', 'Vâng, vậy tôi sẽ mở luôn file QA, xin chờ tôi 1 chút.', '/audio/lessons/lesson-10/s05.m4a', 41, 50, 80),
  ('00000000-0000-0000-0010-000000000006', '00000000-0000-0000-0000-0000000b0010', 5, '映っていますか。', 'Chị thấy chưa?', '/audio/lessons/lesson-10/s06.m4a', 51, 54, 80),
  ('00000000-0000-0000-0010-000000000007', '00000000-0000-0000-0000-0000000b0010', 6, 'はい。見えています。', 'Vâng, tôi thấy rồi', '/audio/lessons/lesson-10/s07.m4a', 54, 59, 80),
  ('00000000-0000-0000-0010-000000000008', '00000000-0000-0000-0000-0000000b0010', 7, '5番のQ&Aはテスト環境についてです。 先日、 iPad Air も対象にするというお話でしたが、テストブラウザは Safari のみでよろしいですか。 それとも Chrome もテストしないといけないですか。 対象にする場合、 テストは最新のバージョンのみで問題ありませんか。それとも一つ前のバージョンもテストする必要がありますか。', 'QA5 là về môi trường Test. Hôm trước đã thảo luận là test với Ipad Air, browser test là chỉ trên Safari có được không? Hay là phải test trên cả Chrome? Nếu phải test thì test với version chrome mới nhất thì ok chứ? Hay là phải test với version trước', '/audio/lessons/lesson-10/s08.m4a', 59, 95, 80),
  ('00000000-0000-0000-0010-000000000009', '00000000-0000-0000-0000-0000000b0010', 8, 'そうですね。 Chromeもお願いします。 バージョンは、最新のものだけでよいです。', 'Vâng, nhờ anh test cả Chrome, version mới nhất cũng được', '/audio/lessons/lesson-10/s09.m4a', 95, 106, 80),
  ('00000000-0000-0000-0010-000000000010', '00000000-0000-0000-0000-0000000b0010', 9, '承知しました。 では、次の6番に行きます。 アプリを操作するときの動きについて相談させてください。 ブラウザでアプリを開くときに、複数のタブやウィンドウで開けないように制限を設けたいです。理由はファイルにも書いた通り、RAM をたくさん使うことになり、パフォーマンスに影響を与える可能性があるからです。', 'Tôi hiểu rồi. Tiếp theo là câu 6, tôi muốn thảo luận về chuyển động khi thao tác app. Khi mở app trên browser, tôi muốn đặt giới hạn để không thể mở ứng dụng đó trong nhiều tab hoặc cửa sổ. Lý do là như tôi đã viết trong file, nó ngốn nhiều RAM và có thể ảnh hưởng đến hiệu năng.', '/audio/lessons/lesson-10/s10.m4a', 106, 143, 80),
  ('00000000-0000-0000-0010-000000000011', '00000000-0000-0000-0000-0000000b0010', 10, '操作には制限をかけたくないのですが、社内で確認してから回答します。', 'Tôi thì không muốn giới hạn thao tác, tôi sẽ xác nhận trong công ty rồi sẽ trả lời', '/audio/lessons/lesson-10/s11.m4a', 143, 152, 80),
  ('00000000-0000-0000-0010-000000000012', '00000000-0000-0000-0000-0000000b0010', 11, '承知しました。 そろそろ終了時間ですので、 残りの質問を含めて、今週中に回答していただけると幸いです。ありがとうございました。', 'Tôi hiểu rồi. Cùng đến giờ rồi, rất mong chị có thể trả lời các câu hỏi còn lại trước cuối tuần này. Cảm ơn rất nhiều.', '/audio/lessons/lesson-10/s12.m4a', 152, 168, 80),
  ('00000000-0000-0000-0010-000000000013', '00000000-0000-0000-0000-0000000b0010', 12, 'はい、では本日はここで終わりましょう。 ありがとうございました。 引き続きよろしくお願いします。', 'Vâng, thế hôm nay kết thúc ở đây. Xin cảm ơn, rất mong anh tiếp tục hỗ trợ.', '/audio/lessons/lesson-10/s13.m4a', 168, 179, 80),
  ('00000000-0000-0000-0011-000000000001', '00000000-0000-0000-0000-0000000b0011', 0, 'では、学習結果確認機能の詳細画面のデモを始めます。よろしくお願いします。', 'Vâng, tôi xin phép được bắt đầu demo màn hình Detail chức năng xác nhận kết quả học tập', '/audio/lessons/lesson-11/s01.m4a', 0, 17, 80),
  ('00000000-0000-0000-0011-000000000002', '00000000-0000-0000-0000-0000000b0011', 1, 'はい、よろしくお願いします。', 'Vâng, xin nhờ anh', '/audio/lessons/lesson-11/s02.m4a', 17, 21, 80),
  ('00000000-0000-0000-0011-000000000003', '00000000-0000-0000-0000-0000000b0011', 2, '詳細画面では、要件通り、画像を上部に配置しています。 画面レイアウトはこれでよいかご確認お願いします。', 'Ở màn hình Detail, hình ảnh được đặt ở trên cùng theo requirement. Vui lòng kiểm tra xem layout màn hình này có đúng không.', '/audio/lessons/lesson-11/s03.m4a', 22, 36, 80),
  ('00000000-0000-0000-0011-000000000004', '00000000-0000-0000-0000-0000000b0011', 3, 'うーん。やはり、画像にボタンが重なってしまうのは避けたいですね。 ここは、そうならないように対応してもらえますか。', 'Ừm. Đúng là nên tránh chồng button lên hình ảnh nhỉ. Bạn có thể đối ứng để tránh điều đó được không?', '/audio/lessons/lesson-11/s04.m4a', 36, 50, 80),
  ('00000000-0000-0000-0011-000000000005', '00000000-0000-0000-0000-0000000b0011', 4, 'そうですね……。ボタンが重ならないように、画像の表示領域を小さくして対応することはできますが、いかがですか。', 'Ùm… Có thể giảm vùng hiển thị của hình ảnh để các button không bị chồng lên nhau, chị nghĩ sao?', '/audio/lessons/lesson-11/s05.m4a', 51, 64, 80),
  ('00000000-0000-0000-0011-000000000006', '00000000-0000-0000-0000-0000000b0011', 5, '可能であれば、 表示領域は変更しないようにしたいです。 デフォルトの画像サイズを小さくして、対応するわけにはいかないですか。', 'Nếu có thể, tôi không muốn thay đổi vùng hiển thị. Bạn có thể đối ứng theo hướng làm nhỏ size ảnh default được không?', '/audio/lessons/lesson-11/s06.m4a', 64, 79, 80),
  ('00000000-0000-0000-0011-000000000007', '00000000-0000-0000-0000-0000000b0011', 6, '実は、アプリの表示枠は画面の縦横の比率に固定しているので、その案での対応は、難しいかと思います。 では、一度持ち帰って、技術的に実現可能か検討してみます。その結果を次の定例会のときに報告してもよろしいですか。', 'Thực ra khung hiển thị của App được cố định theo tỷ lệ khung hình của màn hình, nên tôi nghĩ sẽ khó thực hiện được ý tưởng này. Thôi, chúng tôi sẽ mang về và thử xem xét lại về technical xem có thực hiện được không. Tôi xin phép báo cáo kết quả tại cuộc họp định kỳ tiếp theo được không?', '/audio/lessons/lesson-11/s07.m4a', 79, 109, 80),
  ('00000000-0000-0000-0011-000000000008', '00000000-0000-0000-0000-0000000b0011', 7, 'はい、お願いします。 それと、対応にかかる工数も見積もって報告してください。', 'Vâng, xin nhờ anh. Thêm nữa, xin hãy báo cáo lại công số đối ứng cho tôi.', '/audio/lessons/lesson-11/s08.m4a', 109, 120, 80),
  ('00000000-0000-0000-0011-000000000009', '00000000-0000-0000-0000-0000000b0011', 8, 'はい、承知しました。変更する場合は、いくつか修正する必要が出てくると思います。 画像の拡大縮小やペンツールなどです。 デスクトップ版とWeb版の両方で変更点と変更の工数をまとめて報告します。', 'Vâng, tôi hiểu rồi. Trường hợp có update, tôi nghĩ sẽ cần một số điều chỉnh như thu phóng hình ảnh, pen tool, v.v… Chúng tôi sẽ tổng hợp và báo cáo những điểm thay đổi và công số thay đổi ở bản Desktop và bản Web.', '/audio/lessons/lesson-11/s09.m4a', 120, 145, 80),
  ('00000000-0000-0000-0011-000000000010', '00000000-0000-0000-0000-0000000b0011', 9, 'はい、お待ちしています。', 'Vâng, tôi xin chờ đợi ạ', '/audio/lessons/lesson-11/s10.m4a', 145, 149, 80),
  ('00000000-0000-0000-0012-000000000001', '00000000-0000-0000-0000-0000000b0012', 0, '小巻さん、スケジュールについて相談したいことがありますが、お時間よろしいですか。', 'Chị Komaki, chị có thời gian ko? Tôi có việc muốn thảo luận với chị', '/audio/lessons/lesson-12/s01.m4a', 8, 17, 80),
  ('00000000-0000-0000-0012-000000000002', '00000000-0000-0000-0000-0000000b0012', 1, 'はい。いいですよ。', 'Ok', '/audio/lessons/lesson-12/s02.m4a', 17, 21, 80),
  ('00000000-0000-0000-0012-000000000003', '00000000-0000-0000-0000-0000000b0012', 2, 'Q&Aの6番に関してです。 同じブラウザで複数ウィンドウを開くのに制限をかけないというご要望でしたが、これに対応するには予定よりも時間がかかりそうです。', 'Về câu QA6, có yêu cầu không hạn chế về việc mở nhiều cửa sổ trong cùng 1 browser nhưng có vẻ như sẽ mất nhiều thời gian hơn dự kiến ​​để đối ứng yêu cầu này', '/audio/lessons/lesson-12/s03.m4a', 21, 41, 80),
  ('00000000-0000-0000-0012-000000000004', '00000000-0000-0000-0000-0000000b0012', 3, 'そうですか。時間がかかるということですが、 今回のリリーススケジュールには影響しますか。', 'Thế à? Mất thời gian nhưng có ảnh hưởng đến schedule release lần này không?', '/audio/lessons/lesson-12/s04.m4a', 41, 50, 80),
  ('00000000-0000-0000-0012-000000000005', '00000000-0000-0000-0000-0000000b0012', 4, 'それが、スケジュールに影響しそうなので、 ご相談したいです。 制限をかけないように対応した場合は、 今回のリリースに間に合わないと思っています。', 'Tôi muốn thảo luận vấn đề này vì nó có lẽ sẽ ảnh hưởng đến schedule. Trường hợp mà đối ứng để không hạn chế thì tôi nghĩ sẽ không kịp release lần này', '/audio/lessons/lesson-12/s05.m4a', 52, 69, 80),
  ('00000000-0000-0000-0012-000000000006', '00000000-0000-0000-0000-0000000b0012', 5, 'うーん……そうですか。 対応には、どの程度工数がかかる見込みですか。', 'Vậy à…Việc xử lý thì dự kiến mất bao nhiêu công số', '/audio/lessons/lesson-12/s06.m4a', 69, 79, 80),
  ('00000000-0000-0000-0012-000000000007', '00000000-0000-0000-0000-0000000b0012', 6, 'はい、対応工数を見積もった結果、少なくとも10人目かかる見込みです。そこで、ご相談ですが、今回のリリースは制限を設けたバージョンを納品し、次回のリリースの際に制限なしのバージョンを納品したいです。それで、ご了承いただけないでしょうか。', 'Vâng, sau khi ước tính công số, dự kiến ​​sẽ cần ít nhất 10 người. Vì vậy, tôi muốn nộp một version có limit cho lần bản nộp lần này và một version không có hạn chế trong bản phát hành tiếp theo. Như vậy thì có được không?', '/audio/lessons/lesson-12/s07.m4a', 79, 109, 80),
  ('00000000-0000-0000-0012-000000000008', '00000000-0000-0000-0000-0000000b0012', 7, '1点確認しておきたいのですが、見積り工数は、テストも含めた工数ですか。', 'Tôi có điều muốn xác nhận thêm, công số estimate đã bao gồm test chưa?', '/audio/lessons/lesson-12/s08.m4a', 109, 118, 80),
  ('00000000-0000-0000-0012-000000000009', '00000000-0000-0000-0000-0000000b0012', 8, 'はい、そうです。そのうち3人はテスト工数です。', 'Vâng, trong đó là 3 người test rồi ạ.', '/audio/lessons/lesson-12/s09.m4a', 118, 126, 80),
  ('00000000-0000-0000-0012-000000000010', '00000000-0000-0000-0000-0000000b0012', 9, '状況についてはわかりました。受け入れテストの日程も近いので、一旦、 担当者とも相談します。 回答は早いほうがいいですね。', 'Tôi đã nắm được tình hình. Vì ngày kiểm tra nghiệm thu sắp đến nên tôi sẽ tham khảo ý kiến ​​của người phụ trách. Câu trả lời càng sớm thì càng tốt nhỉ.', '/audio/lessons/lesson-12/s10.m4a', 126, 142, 80),
  ('00000000-0000-0000-0012-000000000011', '00000000-0000-0000-0000-0000000b0012', 10, 'はい、できれば、 明日中にご回答いただけないでしょうか。 どうぞよろしくお願いいたします。', 'Vâng, nếu có thể, chị có thể vui lòng trả lời vào ngày mai được không? Cảm ơn rất nhiều.', '/audio/lessons/lesson-12/s11.m4a', 142, 153, 80),
  ('00000000-0000-0000-0013-000000000001', '00000000-0000-0000-0000-0000000b0013', 0, '昨日は納品していただきありがとうございました。 では、今回の納品についてご説明いただけますか。', 'Cảm ơn bạn đã bàn giao sản phẩm ngày hôm qua. Bạn có thể vui lòng giải thích về việc lần bàn giao này được không?', '/audio/lessons/lesson-13/s01.m4a', 0, 19, 80),
  ('00000000-0000-0000-0013-000000000002', '00000000-0000-0000-0000-0000000b0013', 1, 'はい。 承知しました。 では、 リリースノートの記載内容に沿って説明いたします。', 'Đúng. Tôi hiểu rồi. Bây giờ tôi sẽ giải thích theo nội dung Release note', '/audio/lessons/lesson-13/s02.m4a', 19, 29, 80),
  ('00000000-0000-0000-0013-000000000003', '00000000-0000-0000-0000-0000000b0013', 2, '1点だけお願いですが、デモのときに弊社からあげた要望や御社からのご提案があったと思いますので、その対応についても教えてください', 'Tôi có 1 chỗ cần confirm, khi demo thì cũng có request phía chúng tôi và đề xuất phía công ty bạn, thì hãy cho tôi biết cả về đối ứng những cái đấy', '/audio/lessons/lesson-13/s03.m4a', 30, 47, 80),
  ('00000000-0000-0000-0013-000000000004', '00000000-0000-0000-0000-0000000b0013', 3, 'はい。まず、納品物ですが、 ソースコードとソースコードからビルドしたアプリケーション、そして、ドキュメントをこちらのフォルダに配置しました。 ご要望に応じて、インストール手順書には、アンインストールの手順についても記載しています。', 'Vâng. Đầu tiên, về bàn giao sản phẩm, chúng tôi đã để source code và App đã build từ source code cùng với document trong thư mục này. Theo yêu cầu, ở tài liệu hướng dẫn cài đặt cũng bao gồm hướng dẫn gỡ cài đặt.', '/audio/lessons/lesson-13/s04.m4a', 47, 74, 80),
  ('00000000-0000-0000-0013-000000000005', '00000000-0000-0000-0000-0000000b0013', 4, 'はい、拝見したところ、手順書の中で少しわかりにくい記載があるので、後ほど確認させてください。', 'Vâng, tôi đã xem và thấy trong hướng dẫn các bước có một số thông tin hơi khó hiểu nên vui lòng để tôi kiểm tra lại sau.', '/audio/lessons/lesson-13/s05.m4a', 74, 87, 80),
  ('00000000-0000-0000-0013-000000000006', '00000000-0000-0000-0000-0000000b0013', 5, '今回は、開発の中でいくつか制限事項も残っています。 それについて説明します。iPad 版の学習データ保存機能では、 お気に入り画面に画像が3枚以上あると、 ページが再読み込みされます。 また、 iPad 版の お気に入りに登録できる画像は最大2MB で 10枚までです。', 'Lần này, trong quá trình phát triển vẫn còn lại 1 số mục giới hạn. Hãy để tôi giải thích về nó. Ở chức năng lưu dữ liệu học tập của phiên bản iPad, nếu có ba hình ảnh trở lên trên màn hình yêu thích, page sẽ reload. Ngoài ra, ở bản Ipad bạn có thể thêm tối đa 10 hình ảnh có dung lượng max là 2MB vào mục yêu thích.', '/audio/lessons/lesson-13/s06.m4a', 87, 123, 80),
  ('00000000-0000-0000-0013-000000000007', '00000000-0000-0000-0000-0000000b0013', 6, 'はい。これは以前からご説明がありましたね。', 'Vâng. Điều này đã được giải thích trước đây.', '/audio/lessons/lesson-13/s07.m4a', 123, 129, 80),
  ('00000000-0000-0000-0013-000000000008', '00000000-0000-0000-0000-0000000b0013', 7, 'はい。見積りの際に説明した通り、端末のハードウェアのスペックによるものです。機能は実行できますが、デスクトップ版と比べると動作が重くなります。 そこで、端末のRAM は 4GB 以上を推奨しています。', 'Đúng. Như đã giải thích khi đưa ra estimation, nó phụ thuộc vào thông số kỹ thuật phần cứng của thiết bị. Mặc dù có thể thực hiện functio nhưng hoạt động sẽ chậm hơn so với phiên bản dành cho bản desktop. Do đó, chúng tôi khuyến nghị thiết bị của bạn nên có RAM 4GB trở lên.', '/audio/lessons/lesson-13/s08.m4a', 129, 155, 80),
  ('00000000-0000-0000-0013-000000000009', '00000000-0000-0000-0000-0000000b0013', 8, 'はい。これに関しては弊社でも承知しています。', 'Vâng. Chúng tôi cũng nhận thức được điều này.', '/audio/lessons/lesson-13/s09.m4a', 155, 161, 80),
  ('00000000-0000-0000-0014-000000000001', '00000000-0000-0000-0000-0000000b0014', 0, 'リーさん、今回のUATサポートでお願いしたいことがありますが、いいですか。', 'Chị Ly, tôi muốn hỏi về việc support UAT lần này được không ạ?', '/audio/lessons/lesson-14/s01.m4a', 3, 16, 80),
  ('00000000-0000-0000-0014-000000000002', '00000000-0000-0000-0000-0000000b0014', 1, 'はい。なんでしょうか。', 'Vâng, có việc gì ạ?', '/audio/lessons/lesson-14/s02.m4a', 16, 20, 80),
  ('00000000-0000-0000-0014-000000000003', '00000000-0000-0000-0000-0000000b0014', 2, '先日、成果物を受け取りました。 これから受入テストを行っていきます。 そこで、 不具合が出た場合の体制について、念のためもう一度聞かせてください。', 'Tôi đã nhận được hàng giao vào ngày hôm trước. Bây giờ chúng tôi sẽ tiến hành kiểm thử chấp nhận. Vì vậy, để chắc chắn, tôi muốn hỏi lại bạn về việc đối ứng trường hợp phát sinh bug', '/audio/lessons/lesson-14/s03.m4a', 20, 38, 80),
  ('00000000-0000-0000-0014-000000000004', '00000000-0000-0000-0000-0000000b0014', 3, 'はい。 定例会のときにも相談しましたが、 受入テストで検出された不具合は、まず私が原因を分析することになっています。', 'Vâng. Như tôi đã thảo luận trong cuộc họp định kỳ, khi phát hiện ra bug trong quá trình kiểm thử chấp nhận, tôi là người đầu tiên phân tích nguyên nhân.', '/audio/lessons/lesson-14/s04.m4a', 38, 53, 80),
  ('00000000-0000-0000-0014-000000000005', '00000000-0000-0000-0000-0000000b0014', 4, 'そうでしたね。その後、どちらで対応するのか切り分けするのですね。', 'Vâng, sau đó phía bạn sẽ quyết định nên giải quyết vấn đề nào nhỉ', '/audio/lessons/lesson-14/s05.m4a', 53, 61, 80),
  ('00000000-0000-0000-0014-000000000006', '00000000-0000-0000-0000-0000000b0014', 5, 'はい、その通りです。分析に加えて、私が対応するものとオフショアが対応するものの切り分けもします。 再現手順についても確認します。確認に際して分からないことがあったら、山本さんにお聞きしてもよろしいですか。', 'Vâng đúng vậy. Ngoài việc phân tích, tôi cũng tách biệt những gì tôi giải quyết và những gì đội offshore giải quyết. Chúng tôi cũng xác nhận trình tự tái hiện. Nếu có điều gì tôi không hiểu trong quá trình xác nhận, tôi có thể hỏi ông Yamamoto được không?', '/audio/lessons/lesson-14/s06.m4a', 61, 84, 80),
  ('00000000-0000-0000-0014-000000000007', '00000000-0000-0000-0000-0000000b0014', 6, 'もちろん、いいですよ。 困ったときは、いつでも声をかけてください。', 'Tất nhiên rồi. Nếu bạn gặp khó khăn gì, hãy gọi cho chúng tôi bất cứ lúc nào.', '/audio/lessons/lesson-14/s07.m4a', 84, 91, 80),
  ('00000000-0000-0000-0014-000000000008', '00000000-0000-0000-0000-0000000b0014', 7, 'はい、ありがとうございます。', 'Vâng, xin cảm ơn', '/audio/lessons/lesson-14/s08.m4a', 91, 95, 80),
  ('00000000-0000-0000-0014-000000000009', '00000000-0000-0000-0000-0000000b0014', 8, '不具合が何件か同時に発生した場合は、まず不具合管理システムに登録します。その後、 一旦、弊社で対応の優先順位を決めて、 連絡します。 ですが、リーさんが分析をしたときに優先順位を変更したいものがありましたら、相談に来てください。', 'Nếu có nhiều bug xảy ra cùng lúc, trước tiên hãy log chúng vào hệ thống quản lý bug. Sau đó, chúng tôi sẽ quyết định mức độ ưu tiên đối ứng và liên hệ với bạn. Tuy nhiên, nếu khi chị Ly phân tích có sự thay đổi về thứu tự ưu tiên thì hãy thảo luận với chúng tôi', '/audio/lessons/lesson-14/s09.m4a', 95, 122, 80),
  ('00000000-0000-0000-0014-000000000010', '00000000-0000-0000-0000-0000000b0014', 9, '承知しました。 そう言えば、先日、仕様を少し変えたいというお話がありましたが、具体的に教えていただけますか。', 'Tôi hiểu rồi. À, hôm trước anh có nói là muốn thay đổi 1 chút, hãy cho tôi biết cụ thể được không?', '/audio/lessons/lesson-14/s10.m4a', 123, 136, 80),
  ('00000000-0000-0000-0014-000000000011', '00000000-0000-0000-0000-0000000b0014', 10, 'あ、そうですね。その件に関わる資料を準備していますので、午後、相談しましょう。どれぐらい時間がかかるかを教えていただきたいです。', 'À, đúng rồi. Tôi đang chuẩn bị tài liệu liên quan đến vấn đề này, chiều sẽ bàn tiếp nhé. Tôi muốn biết sẽ mất bao nhiêu thời gian.', '/audio/lessons/lesson-14/s11.m4a', 136, 144, 80),
  ('00000000-0000-0000-0014-000000000012', '00000000-0000-0000-0000-0000000b0014', 11, '承知しました。 準備されたら、お声がけください。 よろしくお願いいたします。', 'Tôi hiểu rồi. Xin vui lòng cho tôi biết khi bạn chuẩn bị xong. Cảm ơn.', '/audio/lessons/lesson-14/s12.m4a', 144, 149, 80),
  ('00000000-0000-0000-0015-000000000001', '00000000-0000-0000-0000-0000000b0015', 0, '皆さん、ちょっといいですか。 作業の手を止めてこちらへ集まってください。', 'Mọi người, tôi xin một chút thời gian được không ạ? Hãy dừng công việc của bạn và tập trung ở đây.', '/audio/lessons/lesson-15/s01.m4a', 6, 16, 80),
  ('00000000-0000-0000-0015-000000000002', '00000000-0000-0000-0000-0000000b0015', 1, 'デジタル教科書アプリの受入テストと展開も無事終わりました。 本日はリーさんのオンサイト最終日です。リーさん、これまで約4か月間お疲れさまでした。', 'Quá trình nghiệm thu và triển khai ứng dụng sách kỹ thuật số đã hoàn tất thành công. Hôm nay là ngày cuối cùng chị Ly ở đây. Ông Lee, cảm ơn vì đã làm việc chăm chỉ trong bốn tháng qua.', '/audio/lessons/lesson-15/s02.m4a', 16, 37, 80),
  ('00000000-0000-0000-0015-000000000003', '00000000-0000-0000-0000-0000000b0015', 2, 'はい、皆様、オンサイト中はいろいろとお世話になり、ありがとうございました。 おかげさまで、受入テストの間、大きな不具合もなく、本日を迎えることができました。', 'Vâng, xin cảm ơn rất nhiều vì tất cả sự giúp đỡ của bạn trong thời gian tôi onsite. Nhờ có các bạn, chúng ta đã đến được ngày hôm nay mà không gặp bất kỳ vấn đề lớn nào trong quá trình kiểm thử chấp nhận.', '/audio/lessons/lesson-15/s03.m4a', 37, 55, 80),
  ('00000000-0000-0000-0015-000000000004', '00000000-0000-0000-0000-0000000b0015', 3, 'そうですね。リーさんがいてくれたので、技術面で課題が出てきたときもスムーズに会話ができ、 対応も早かったですね。 来週は振り返り会議をすることになっていますが、そこでも良かった点として報告させてもらいます。', 'Vâng. Nhờ có chị Ly ở đây nên khi có vấn đề kỹ thuật phát sinh, chúng tôi có thể trao đổi suôn sẻ và đối ứng nhanh chóng. Chúng tôi dự kiến ​​sẽ có một cuộc họp tổng kết vào tuần tới và báo cáo về những điểm tốt ở đó.', '/audio/lessons/lesson-15/s04.m4a', 56, 82, 80),
  ('00000000-0000-0000-0015-000000000005', '00000000-0000-0000-0000-0000000b0015', 4, 'ありがとうございます。 本日の定例会で話があった通り、帰国したらチーム全員で良かった点、改善すべき点について相談し、まとめます。', 'Cảm ơn. Như đã thảo luận tại cuộc họp thường kỳ hôm nay, khi về nước, toàn team sẽ thảo luận về những điểm tốt, những điểm cần cải thiện và tổng hợp kết quả.', '/audio/lessons/lesson-15/s05.m4a', 82, 97, 80),
  ('00000000-0000-0000-0015-000000000006', '00000000-0000-0000-0000-0000000b0015', 5, 'はい、弊社でもまとめておきますので、来週の会議では、今後のプロジェクトに向けて見直すべきところについても検討しましょう。', 'Vâng, chúng tôi cũng sẽ tổng hợp lại, vì vậy tại cuộc họp tuần tới, chúng ta hãy xem xét những gì cần sửa đổi cho các dự án trong tương lai.', '/audio/lessons/lesson-15/s06.m4a', 97, 111, 80),
  ('00000000-0000-0000-0015-000000000007', '00000000-0000-0000-0000-0000000b0015', 6, 'はい、よろしくお願いします。', 'Vâng cám ơn các bạn rất nhiều.', '/audio/lessons/lesson-15/s07.m4a', 111, 115, 80),
  ('00000000-0000-0000-0015-000000000008', '00000000-0000-0000-0000-0000000b0015', 7, '現在は調整中で、まだ確定していませんが、 次はもう少し規模の大きなプロジェクトを実施する予定です。確定すれば、クラウドの人材など要員追加を依頼することになると思います。詳しいことが決まったら、また御社に連絡しますね。リーさん、次のプロジェクトもよろしくお願いしますね。', 'Chúng tôi hiện đang thực hiện các điều chỉnh và chưa quyết định bất kỳ điều gì, nhưng chúng tôi đang có kế hoạch thực hiện một dự án lớn hơn một chút vào lần tới. Sau khi được xác định, tôi nghĩ chúng tôi sẽ yêu cầu bổ sung nhân sự như nhân sự Cloud. Khi chúng tôi đã quyết định xong các chi tiết, chúng tôi sẽ liên hệ lại với công ty của bạn. Chị Ly, tôi rất mong được làm việc với chị trong dự án tiếp theo.', '/audio/lessons/lesson-15/s08.m4a', 115, 150, 80),
  ('00000000-0000-0000-0015-000000000009', '00000000-0000-0000-0000-0000000b0015', 8, 'はい。こちらこそよろしくお願いいたします。', 'Vâng. Tôi cũng rất hân hạnh ạ.', '/audio/lessons/lesson-15/s09.m4a', 150, 154, 80)
