-- ============================================================================
--  Official resource seed generated from resources/lesson.md + resources/*.m4a
--  Generated by scripts/build-resource-seed-sql.mjs.
--  Run after supabase/schema.sql.
-- ============================================================================

begin;

-- Replace old public starter/sample lessons with the real resource set.
delete from public.lessons where user_id is null and is_public = true;

-- Single official course that groups every resource lesson.
on conflict (id) do update set
  title = excluded.title,
  description = excluded.description,
  topic = excluded.topic,
  level = excluded.level,
  accent = excluded.accent,
  image_url = excluded.image_url,
  is_public = excluded.is_public;

on conflict (id) do update set
  course_id = excluded.course_id,
  title = excluded.title,
  topic = excluded.topic,
  level = excluded.level,
  duration_seconds = excluded.duration_seconds,
  source_type = excluded.source_type,
  source_url = excluded.source_url,
  media_url = excluded.media_url,
  is_public = excluded.is_public;

on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  order_index = excluded.order_index,
  ja_text = excluded.ja_text,
  vi_translation = excluded.vi_translation,
  audio_url = excluded.audio_url,
  audio_start = excluded.audio_start,
  audio_end = excluded.audio_end,
  pass_score = excluded.pass_score;

commit;
